const filterByActiveLocation = (rows = []) => {
  if (activeLocation === "all" || !activeLocation) {
    return rows || [];
  }

  return (rows || []).filter((row) => {
    const location =
      row.location ||
      row.location_name ||
      row.store ||
      row.store_name ||
      row.restaurant_location ||
      "Main Location";

    return (
      String(location).trim().toLowerCase() ===
      String(activeLocation).trim().toLowerCase()
    );
  });
};
