const getSaleDate = (sale = {}) => {
  const rawDate =
    sale.sale_date ??
    sale.date ??
    sale.order_date ??
    sale.created_at ??
    sale.timestamp ??
    sale.day;

  const parsed = rawDate ? new Date(rawDate) : null;

  return parsed && !isNaN(parsed.getTime()) ? parsed : null;
};
