const shiftPerformanceData = shiftLaborRows.reduce((acc, row) => {
  const shiftLabel =
    row.shift ||
    row.Shift ||
    row.daypart ||
    row.Daypart ||
    "Unknown Shift";

  const laborCost = Number(
    row.labor_cost ||
      row.laborCost ||
      row.cost ||
      row.Cost ||
      row["Labor Cost"] ||
      0
  );

  const hours = Number(
    row.hours_worked ||
      row.hours ||
      row.Hours ||
      row["Hours Worked"] ||
      0
  );

  const orders = Number(row.orders_handled || row.orders || 0);

  if (!acc[shiftLabel]) {
    acc[shiftLabel] = {
      shift: shiftLabel,
      revenue: 0,
      orders: 0,
      laborCost: 0,
      hours: 0,
      rows: 0,
    };
  }

  acc[shiftLabel].laborCost += laborCost;
  acc[shiftLabel].hours += hours;
  acc[shiftLabel].orders += orders;
  acc[shiftLabel].rows += 1;
acc[shiftLabel].revenue += Number(
  row.sales_generated ||
    row.revenue_during_shift ||
    row.shift_revenue ||
    row.revenue ||
    0
);
  return acc;
}, {});
Object.values(shiftPerformanceData).forEach((shift) => {
  const laborShare =
    totalShiftLaborCost > 0 ? shift.laborCost / totalShiftLaborCost : 0;

  const actualShiftRevenue = Number(shift.revenue || 0);

  shift.revenue =
    actualShiftRevenue > 0
      ? actualShiftRevenue
      : totalShiftRevenue * laborShare;

  if (!shift.orders || shift.orders <= 0) {
    shift.orders = Math.max(1, Math.round(shift.rows || 1));
  }
});

