const inventoryDepletionData = (inventorySourceRows || []).map((item) => {
  const quantity = Number(
    item.quantity ||
      item.stock ||
      item.current_stock ||
      item.inventory ||
      item.on_hand ||
      item["On Hand"] ||
      0
  );

  const unitCost = Number(
    item.unit_cost ||
      item.cost ||
      item.price ||
      0
  );

  const parLevel = Number(
    item.par_level ||
      item.par ||
      item.target_stock ||
      0
  );

  const reorderPoint = Number(
    item.reorder_point ||
      item.reorder ||
      item.minimum ||
      item.min ||
      0
  );

  const usageRate = Number(
    item.daily_usage ||
      item.avg_daily_usage ||
      item.usage ||
      item.usageRate ||
      0
  );

  const daysRemaining =
    usageRate > 0
      ? Number((quantity / usageRate).toFixed(1))
      : 0;

  let depletionStatus = "Healthy";

const lowStockThreshold =
  reorderPoint > 0
    ? reorderPoint
    : parLevel > 0
    ? parLevel * 0.5
    : 0;

if (quantity <= 0) {
  depletionStatus = "Critical";
} else if (reorderPoint > 0 && quantity <= reorderPoint) {
  depletionStatus = "Critical";
} else if (lowStockThreshold > 0 && quantity <= lowStockThreshold) {
  depletionStatus = "Low";
} else if (usageRate > 0 && daysRemaining <= 2) {
  depletionStatus = "Critical";
} else if (usageRate > 0 && daysRemaining <= 5) {
  depletionStatus = "Low";
}

  return {
    ...item,

    name:
      item.name ||
      item.item_name ||
      item.ingredient ||
      item.product ||
      "Inventory Item",

    item_name:
      item.item_name ||
      item.name ||
      item.ingredient ||
      item.product ||
      "Inventory Item",

    category:
      item.category ||
      item.type ||
      "Inventory",

    quantity,

    unit:
      item.unit ||
      item.uom ||
      item.measure ||
      "",

    unitCost,
    unit_cost: unitCost,

    total_value:
      Number(item.total_value || item.value || 0) ||
      quantity * unitCost,

    parLevel,
    par_level: parLevel,

    reorderPoint,
    reorder_point: reorderPoint,

    usageRate,
    daysRemaining,
    depletionStatus,
  };
});

