const spoilageForecastData = useMemo(() => {
  const ingredients =
    uploadComparison?.activeIngredients ||
    ingredientsData ||
    [];

  const getDefaultShelfLife = (name = "") => {
    const item = String(name).toLowerCase();

    if (
      item.includes("seafood") ||
      item.includes("fish") ||
      item.includes("shrimp") ||
      item.includes("salmon") ||
      item.includes("lobster")
    ) {
      return 2;
    }

    if (
      item.includes("chicken") ||
      item.includes("beef") ||
      item.includes("steak") ||
      item.includes("pork")
    ) {
      return 4;
    }

    if (
      item.includes("lettuce") ||
      item.includes("tomato") ||
      item.includes("produce") ||
      item.includes("fruit") ||
      item.includes("vegetable")
    ) {
      return 5;
    }

    if (
      item.includes("cheese") ||
      item.includes("milk") ||
      item.includes("cream") ||
      item.includes("dairy")
    ) {
      return 7;
    }

    return 10;
  };

  return ingredients.map((item) => {
    const name =
      item.name ||
      item.ingredient_name ||
      item.item_name ||
      "Unknown Ingredient";

    const receivedDateRaw =
      item.received_date ||
      item.receivedDate ||
      item.purchase_date ||
      item["Purchase Date"] ||
      item.created_at ||
      null;

    const receivedDate = receivedDateRaw
      ? new Date(receivedDateRaw)
      : new Date();

    const shelfLifeDays = Number(
      item.shelf_life_days ||
        item.shelfLifeDays ||
        item["Shelf Life Days"] ||
        getDefaultShelfLife(name)
    );

    const expirationDate = new Date(receivedDate);
    expirationDate.setDate(expirationDate.getDate() + shelfLifeDays);

    const today = new Date();
    const daysUntilSpoilage = Math.ceil(
      (expirationDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
    );

    let status = "Healthy";
    let recommendation = "Shelf life risk looks controlled.";

    if (daysUntilSpoilage <= 0) {
      status = "Expired Risk";
      recommendation = "Review immediately. This item may already be spoiled.";
    } else if (daysUntilSpoilage <= 2) {
      status = "Spoilage Risk";
      recommendation = "Prioritize this ingredient in specials or prep planning.";
    } else if (daysUntilSpoilage <= 4) {
      status = "Watch";
      recommendation = "Monitor this item and avoid over-prepping.";
    }

    return {
      name,
      receivedDate,
      shelfLifeDays,
      expirationDate,
      daysUntilSpoilage,
      status,
      recommendation,
    };
  });
}, [uploadComparison, ingredientsData]);

const vendorPriceSpikeData = useMemo(() => {
  const invoiceRows =
    invoicesData ||
    invoiceData ||
    [];

  const grouped = {};

  invoiceRows.forEach((invoice) => {
    const itemName =
      invoice.item_name ||
      invoice.item ||
      invoice.ingredient_name ||
      invoice.product ||
      invoice.description ||
      "Unknown Item";

    const vendor =
      invoice.vendor ||
      invoice.vendor_name ||
      invoice.supplier ||
      invoice.supplier_name ||
      "Unknown Vendor";

    const dateRaw =
      invoice.invoice_date ||
      invoice.date ||
      invoice.created_at ||
      invoice.purchase_date ||
      null;

    const date = dateRaw ? new Date(dateRaw) : new Date();

    const unitCost = Number(
      invoice.unit_cost ||
        invoice.cost_per_unit ||
        invoice.price_per_unit ||
        invoice.price ||
        invoice.cost ||
        0
    );

    const key = `${vendor}-${itemName}`;

    if (!grouped[key]) {
      grouped[key] = [];
    }

    grouped[key].push({
      itemName,
      vendor,
      date,
      unitCost,
    });
  });

  return Object.values(grouped)
    .map((rows) => {
      const sorted = rows.sort((a, b) => a.date - b.date);

      const previous = sorted[sorted.length - 2];
      const latest = sorted[sorted.length - 1];

      const priceChange =
        previous?.unitCost > 0
          ? ((latest.unitCost - previous.unitCost) / previous.unitCost) * 100
          : 0;

      let status = "Stable";
      let recommendation = "Vendor pricing looks stable.";

      if (priceChange > 20) {
        status = "Critical Spike";
        recommendation = "Review invoice immediately or renegotiate vendor pricing.";
      } else if (priceChange > 10) {
        status = "Price Spike";
        recommendation = "Compare supplier pricing and monitor next invoice.";
      } else if (priceChange > 5) {
        status = "Watch";
        recommendation = "Small price increase detected. Continue monitoring.";
      }

      return {
        itemName: latest?.itemName || "Unknown Item",
        vendor: latest?.vendor || "Unknown Vendor",
        previousCost: previous?.unitCost || 0,
        latestCost: latest?.unitCost || 0,
        priceChange,
        status,
        recommendation,
      };
    })
    .filter((item) => item.latestCost > 0)
    .sort((a, b) => b.priceChange - a.priceChange);
}, [invoicesData]);

const recipeCostingData = useMemo(() => {
  const rules = recipeUsageRules || [];

  const ingredients =
    uploadComparison?.activeIngredients ||
    locationIngredientsData ||
    [];

  const menuItems = locationMenuItemsData || [];

  return menuItems.map((menuItem) => {
    const itemName =
      menuItem.name ||
      menuItem.item_name ||
      menuItem["Item Name"] ||
      "Unknown Item";

    const price = Number(
      menuItem.price ||
        menuItem.menu_price ||
        menuItem["Price"] ||
        0
    );

    const linkedRules = rules.filter(
      (rule) =>
        String(rule.menu_item || rule.menuItem || "")
          .toLowerCase()
          .trim() ===
        String(itemName || "")
          .toLowerCase()
          .trim()
    );

    const calculatedRecipeCost = linkedRules.reduce((sum, rule) => {
      const ingredient = ingredients.find(
        (ing) =>
          String(
            ing.name ||
              ing.ingredient_name ||
              ""
          )
            .toLowerCase()
            .trim() ===
          String(rule.ingredient || "")
            .toLowerCase()
            .trim()
      );

      const costPerUnit = Number(
        ingredient?.cost_per_unit ||
          ingredient?.costPerUnit ||
          ingredient?.unit_cost ||
          ingredient?.price_per_unit ||
          ingredient?.cost ||
          0
      );

      return (
        sum +
        Number(
          rule.quantity_used ||
            rule.amountUsed ||
            0
        ) *
          costPerUnit
      );
    }, 0);

    const uploadedCost = Number(
      menuItem.cost ||
        menuItem.recipe_cost ||
        menuItem.food_cost ||
        menuItem["Food Cost"] ||
        menuItem["Cost"] ||
        0
    );

    const recipeCost =
      calculatedRecipeCost > 0
        ? calculatedRecipeCost
        : uploadedCost;

    const profit = price - recipeCost;

    const margin =
      price > 0
        ? (profit / price) * 100
        : 0;

    let status = "Needs Price Data";

    let recommendation =
      "Add menu price and recipe rules to calculate true margin.";

    if (price > 0 && margin >= 70) {
      status = "High Profit";
      recommendation =
        "Promote this item. It has strong recipe profitability.";
    } else if (price > 0 && margin >= 60) {
      status = "Healthy";
      recommendation =
        "Margin is healthy. Monitor ingredient cost changes.";
    } else if (price > 0 && margin >= 50) {
      status = "Watch";
      recommendation =
        "Review pricing or ingredient portions.";
    } else if (price > 0) {
      status = "Low Margin";
      recommendation =
        "Adjust price, reduce portion cost, or renegotiate ingredients.";
    }

    return {
      itemName,
      price,
      recipeCost,
      profit,
      margin,
      status,
      recommendation,
      ingredientCount: linkedRules.length,
    };
  });
}, [
  recipeUsageRules,
  uploadComparison,
  locationIngredientsData,
  locationMenuItemsData,
]);
