const happyHourProfitabilityData = useMemo(() => {
  const beverageSales =
    alcoholSalesRows ||
    locationSalesData ||
    salesData ||
    [];

  const happyHourSales = beverageSales.filter((sale) => {
    const saleHour = new Date(
      sale.created_at ||
        sale.date ||
        sale.sale_date ||
        Date.now()
    ).getHours();

    return saleHour >= 15 && saleHour <= 18;
  });

  const totalRevenue = happyHourSales.reduce(
    (sum, sale) =>
      sum +
      Number(
        sale.revenue ||
          sale.total ||
          sale.amount ||
          sale.price ||
          0
      ),
    0
  );

  const totalCost = happyHourSales.reduce(
    (sum, sale) =>
      sum +
      Number(
        sale.cost ||
          sale.item_cost ||
          sale.cogs ||
          0
      ),
    0
  );

  const discountImpact = happyHourSales.reduce(
    (sum, sale) =>
      sum +
      Number(
        sale.discount_amount ||
          sale.discount ||
          0
      ),
    0
  );

  const grossProfit = totalRevenue - totalCost;
  const marginPercent =
    totalRevenue > 0 ? (grossProfit / totalRevenue) * 100 : 0;

  let status = "Profitable";

  if (marginPercent < 45) {
    status = "Margin Leak";
  } else if (marginPercent < 58) {
    status = "Review";
  } else if (discountImpact > totalRevenue * 0.18) {
    status = "Discount Heavy";
  }

  return {
    salesCount: happyHourSales.length,
    totalRevenue,
    totalCost,
    discountImpact,
    grossProfit,
    marginPercent,
    status,
  };
}, [
  alcoholSalesRows,
  locationSalesData,
  salesData,
]);

