const overtimeRiskData = useMemo(() => {
  const rows =
  locationLaborData?.length
    ? locationLaborData
    : laborData || [];

  const overtimeRows = rows
    .map((row, index) => {
      const hours = Number(
        row.overtime_hours ||
          row.overtimeHours ||
          row["Overtime Hours"] ||
          row.ot_hours ||
          row["OT Hours"] ||
          0
      );

      const rate = Number(
        row.hourly_rate ||
          row.hourlyRate ||
          row.rate ||
          row["Hourly Rate"] ||
          0
      );

      const estimatedOvertimeCost =
        Number(
          row.overtime_cost ||
            row.overtimeCost ||
            row["Overtime Cost"] ||
            row.ot_cost ||
            row["OT Cost"] ||
            0
        ) || hours * rate * 1.5 || 0;

      const name =
        row.employee_name ||
        row.employee ||
        row.name ||
        row.staff_name ||
        row.role ||
        `Labor Row ${index + 1}`;

      return {
        name,
        hours: Number(row.hours_worked || row.hours || 0),
        laborCost: Number(row.labor_cost || row.cost || 0),
        projectedOvertimeHours: hours,
        estimatedOvertimeCost,
        status: hours > 0 ? "Overtime" : "Controlled",
      };
    })
    .filter(
      (employee) =>
        Number(employee.projectedOvertimeHours || 0) > 0 ||
        Number(employee.estimatedOvertimeCost || 0) > 0
    );

  return overtimeRows.sort(
    (a, b) =>
      Number(b.estimatedOvertimeCost || 0) -
      Number(a.estimatedOvertimeCost || 0)
  );
}, [laborData, locationLaborData]);

const laborForecastingData = useMemo(() => {
  const shifts = shiftOperationalData || [];

  if (!shifts.length) {
    return [];
  }

  return shifts.map((shift) => {
    const revenue = Number(shift.revenue || 0);
    const laborCost = Number(shift.laborCost || 0);
    const laborPercent = Number(shift.laborPercent || 0);
    const orders = Number(shift.orders || 0);
const projectedRevenue = revenue;
const projectedLaborCost = laborCost * 1.06;

    const projectedLaborPercent =
      projectedRevenue > 0 ? (projectedLaborCost / projectedRevenue) * 100 : 0;

    const projectedOrders = orders * 1.07;

    let forecastStatus = "Stable";

    if (projectedLaborPercent > 38) {
      forecastStatus = "Critical";
    } else if (projectedLaborPercent > 32) {
      forecastStatus = "Watch";
    } else if (projectedLaborPercent < 24 && projectedRevenue > 0) {
      forecastStatus = "Efficient";
    }

    return {
      shift: shift.shift,
      projectedRevenue,
      projectedLaborCost,
      projectedLaborPercent,
      projectedOrders,
      forecastStatus,
      currentLaborPercent: laborPercent,
    };
  });
}, [shiftOperationalData]);
