const renderSafeText = (value, fallback = "") => {
  if (value === null || value === undefined) return fallback;

  if (typeof value === "object") {
    return (
      value.title ||
      value.message ||
      value.description ||
      value.action ||
      fallback
    );
  }

  return value;
};
