const peakDiningHour = (() => {
  const rows = salesData?.length ? salesData : locationSalesData || [];

  const hourCounts = {};

  rows.forEach((sale) => {
    const rawDate =
      sale.created_at ||
      sale.sale_date ||
      sale.date ||
      sale.order_time ||
      sale.timestamp;

    if (!rawDate) return;

    const hour = new Date(rawDate).getHours();

    if (Number.isNaN(hour)) return;

    hourCounts[hour] = (hourCounts[hour] || 0) + 1;
  });

  const peakHour = Object.entries(hourCounts).sort(
    (a, b) => b[1] - a[1]
  )[0]?.[0];

  if (!peakHour) return null;

  const hourNumber = Number(peakHour);
  const displayHour =
    hourNumber === 0
      ? "12 AM"
      : hourNumber === 12
      ? "12 PM"
      : hourNumber > 12
      ? `${hourNumber - 12} PM`
      : `${hourNumber} AM`;

  return displayHour;
})();

const peakDiningDay = (() => {
  const rows = salesData?.length ? salesData : locationSalesData || [];

  const dayCounts = {};

  rows.forEach((sale) => {
    const rawDate =
      sale.created_at ||
      sale.sale_date ||
      sale.date ||
      sale.order_time ||
      sale.timestamp;

    if (!rawDate) return;

    const day = new Date(rawDate).toLocaleDateString("en-US", {
      weekday: "long",
    });

    if (!day || day === "Invalid Date") return;

    dayCounts[day] = (dayCounts[day] || 0) + 1;
  });

  return Object.entries(dayCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || null;
})();

const topCustomerSegment = (() => {
  const rows = salesData?.length ? salesData : locationSalesData || [];

  const segmentCounts = {};

  rows.forEach((sale) => {
    const segment =
      sale.customer_segment ||
      sale.guest_category ||
      sale.customer_type ||
      sale.segment ||
      sale.category;

    if (!segment) return;

    segmentCounts[segment] = (segmentCounts[segment] || 0) + 1;
  });

  return (
    Object.entries(segmentCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || null
  );
})();

const repeatVisitRate = (() => {
  const rows = salesData?.length ? salesData : locationSalesData || [];

  const guestVisits = {};

  rows.forEach((sale) => {
    const guestId =
      sale.customer_id ||
      sale.guest_id ||
      sale.customer_email ||
      sale.email ||
      sale.phone;

    if (!guestId) return;

    guestVisits[guestId] = (guestVisits[guestId] || 0) + 1;
  });

  const guests = Object.values(guestVisits);

  if (!guests.length) return null;

  const repeatGuests = guests.filter((count) => count > 1).length;

  return Math.round((repeatGuests / guests.length) * 100);
})();

